   181→    p->state = PROC_READY;
   182→    p->next = NULL;
   183→    if (ready_tail == NULL) {
   184→        ready_head = ready_tail = p;
   185→    } else {
   186→        ready_tail->next = p;
   187→        ready_tail = p;
   188→    }
   189→}
