   191→static struct pcb *dequeue_ready(void) {
   192→    if (ready_head == NULL) return NULL;
   193→    struct pcb *p = ready_head;
   194→    ready_head = p->next;
   195→    if (ready_head == NULL) ready_tail = NULL;
   196→    p->next = NULL;
   197→    return p;
   198→}
