   200→/* =====================================================================
   201→ *  Context switch callback
   202→ * ===================================================================== */
   203→
   204→static SavedContext *DoSwitch(SavedContext *ctxp, void *p1, void *p2) {
   205→    struct pcb *old = (struct pcb *)p1;
   206→    struct pcb *newer = (struct pcb *)p2;
   207→
   208→    if (old != NULL) {
   209→        old->ctx = *ctxp;
   210→        old->ctx_valid = 1;
   211→    }
   212→
   213→    if (newer == NULL) {
   214→        /* Save-only: no actual switch */
   215→        return ctxp;
   216→    }
   217→
   218→    /* Switch Region 0 page table */
   219→    WriteRegister(REG_PTR0, (RCS421RegVal)(newer->r0pt));
   220→    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
   221→
   222→    current = newer;
   223→    return &newer->ctx;
   224→}
