   226→/*
   227→ * Switch from 'from' to 'to'. Both must have valid ctx (or to == NULL for
   228→ * save-only). 'from' is placed in appropriate queue before calling.
   229→ */
   230→static void do_context_switch(struct pcb *from, struct pcb *to) {
   231→    if (to == NULL) {
   232→        /* Save only */
   233→        ContextSwitch(DoSwitch, &from->ctx, (void *)from, NULL);
   234→        return;
   235→    }
   236→    to->state = PROC_RUNNING;
   237→    ContextSwitch(DoSwitch, &from->ctx, (void *)from, (void *)to);
   238→}
