   314→/* =====================================================================
   315→ *  SetKernelBrk
   316→ * ===================================================================== */
   317→
   318→int SetKernelBrk(void *addr) {
   319→    if (!vm_enabled) {
   320→        /* Before VM: just track break */
   321→        if ((unsigned long)addr > (unsigned long)kernel_brk) {
   322→            kernel_brk = addr;
   323→        }
   324→        return 0;
   325→    }
   326→
   327→    /* After VM: allocate/free physical pages as needed */
   328→    unsigned long new_brk = (unsigned long)UP_TO_PAGE(addr);
   329→    unsigned long cur_brk = (unsigned long)UP_TO_PAGE(kernel_brk);
   330→
   331→    if (new_brk == cur_brk) {
   332→        kernel_brk = addr;
   333→        return 0;
   334→    }
   335→
   336→    if (new_brk > cur_brk) {
   337→        /* Grow kernel heap */
   338→        unsigned long va = cur_brk;
   339→        while (va < new_brk) {
   340→            int vpn = ((long)va - VMEM_1_BASE) >> PAGESHIFT;
   341→            if (vpn < 0 || vpn >= PAGE_TABLE_LEN) return -1;
   342→            if (!kernel_pt[vpn].valid) {
   343→                int pfn = pfn_alloc();
   344→                if (pfn == -1) return -1;
   345→                kernel_pt[vpn].valid = 1;
   346→                kernel_pt[vpn].kprot = PROT_READ | PROT_WRITE;
   347→                kernel_pt[vpn].uprot = PROT_NONE;
   348→                kernel_pt[vpn].pfn   = pfn;
   349→                WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)va);
   350→            }
   351→            va += PAGESIZE;
   352→        }
   353→    } else {
   354→        /* Shrink kernel heap */
   355→        unsigned long va = new_brk;
   356→        while (va < cur_brk) {
   357→            int vpn = ((long)va - VMEM_1_BASE) >> PAGESHIFT;
   358→            if (vpn >= 0 && vpn < PAGE_TABLE_LEN && kernel_pt[vpn].valid) {
   359→                pfn_free(kernel_pt[vpn].pfn);
   360→                kernel_pt[vpn].valid = 0;
   361→                WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)va);
   362→            }
   363→            va += PAGESIZE;
   364→        }
   365→    }
   366→
   367→    kernel_brk = addr;
   368→    return 0;
   369→}
