   906→/* ---------- TRAP_KERNEL (system calls) ---------- */
   907→
   908→static void KernelFork(ExceptionInfo *info);
   909→static void KernelExec(ExceptionInfo *info);
   910→static void KernelExit(ExceptionInfo *info);
   911→static void KernelWait(ExceptionInfo *info);
   912→static void KernelGetPid(ExceptionInfo *info);
   913→static void KernelBrk(ExceptionInfo *info);
   914→static void KernelDelay(ExceptionInfo *info);
   915→static void KernelTtyRead(ExceptionInfo *info);
   916→static void KernelTtyWrite(ExceptionInfo *info);
   917→
   918→static void TrapKernel(ExceptionInfo *info) {
   919→    switch (info->code) {
   920→    case YALNIX_FORK:    KernelFork(info);   break;
   921→    case YALNIX_EXEC:    KernelExec(info);   break;
   922→    case YALNIX_EXIT:    KernelExit(info);   break;
   923→    case YALNIX_WAIT:    KernelWait(info);   break;
   924→    case YALNIX_GETPID:  KernelGetPid(info); break;
   925→    case YALNIX_BRK:     KernelBrk(info);    break;
   926→    case YALNIX_DELAY:   KernelDelay(info);  break;
   927→    case YALNIX_TTY_READ:  KernelTtyRead(info);  break;
   928→    case YALNIX_TTY_WRITE: KernelTtyWrite(info); break;
   929→    default:
   930→        TracePrintf(0, "TrapKernel: unknown call %d\n", info->code);
   931→        info->regs[0] = (unsigned long)ERROR;
   932→        break;
   933→    }
   934→}
