   953→            /* Parent was waiting */
   954→            par->state = PROC_RUNNING;
   955→            enqueue_ready(par);
   956→        }
   957→    }
   958→
   959→    free_user_pages(dying);
   960→    dying->state = PROC_ZOMBIE;
