   967→    struct pcb *next = pick_next();
   968→    next->state = PROC_RUNNING;
   969→    /* Must switch to a valid process */
   970→    WriteRegister(REG_PTR0, (RCS421RegVal)(next->r0pt));
   971→    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
