  1007→/* ---------- TRAP_MEMORY ---------- */
  1008→
  1009→static void TrapMemory(ExceptionInfo *info) {
  1010→    unsigned long addr = (unsigned long)info->addr;
  1011→
  1012→    /* Is it a stack growth request? */
  1013→    unsigned long stk_limit = USER_STACK_LIMIT;
  1014→    unsigned long brk_limit = (unsigned long)current->user_brk_pg << PAGESHIFT;
  1015→
  1016→    if (addr >= brk_limit + PAGESIZE &&  /* above break (with red zone) */
  1017→        addr < stk_limit &&              /* below user stack limit */
  1018→        addr >= MEM_INVALID_SIZE) {
  1019→
  1020→        /* Grow stack to cover addr */
  1021→        int new_vpn = (int)(addr >> PAGESHIFT);
  1022→        int old_low = current->user_stk_low;
  1023→
  1024→        for (int vpn = new_vpn; vpn < old_low; vpn++) {
  1025→            if (current->r0pt[vpn].valid) continue;
  1026→            int pfn = pfn_alloc();
  1027→            if (pfn == -1) {
  1028→                TracePrintf(0, "TrapMemory: out of memory growing stack\n");
  1029→                goto kill;
  1030→            }
  1031→            current->r0pt[vpn].valid = 1;
  1032→            current->r0pt[vpn].kprot = PROT_READ | PROT_WRITE;
  1033→            current->r0pt[vpn].uprot = PROT_READ | PROT_WRITE;
  1034→            current->r0pt[vpn].pfn   = pfn;
  1035→            WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)((long)vpn << PAGESHIFT));
  1036→        }
  1037→        current->user_stk_low = new_vpn;
  1038→        return;  /* Resume */
  1039→    }
  1040→
  1041→kill:
  1042→    TracePrintf(0, "TrapMemory: pid=%d addr=%p - killing\n",
  1043→                current->pid, info->addr);
  1044→    /* Treat as fatal */
  1045→    {
  1046→        ExceptionInfo fake = *info;
  1047→        fake.code = YALNIX_EXIT;
  1048→        fake.regs[1] = (unsigned long)ERROR;
  1049→        TrapIllegal(&fake);
  1050→        /* Copy back any changes */
  1051→        *info = fake;
  1052→    }
  1053→}
