  1312→/* ---------- Exit ---------- */
  1313→
  1314→static void do_exit(struct pcb *dying, int status) {
  1315→    TracePrintf(1, "Exit: pid=%d status=%d\n", dying->pid, status);
  1316→
  1317→    /* Orphan children (remove parent pointer) */
  1318→    for (int i = 0; i < MAX_PROCS; i++) {
  1319→        if (proc_pool_used[i] && proc_pool[i].parent == dying) {
  1320→            proc_pool[i].parent = NULL;
  1321→        }
  1322→    }
  1323→
  1324→    /* Free zombie children (no one will collect them) */
  1325→    struct pcb *zc = dying->zombie_list;
  1326→    while (zc != NULL) {
  1327→        struct pcb *nxt = zc->zombie_next;
  1328→        free_all_r0_pages(zc);
  1329→        free_pcb(zc);
  1330→        zc = nxt;
  1331→    }
  1332→    dying->zombie_list = NULL;
  1333→
  1334→    free_user_pages(dying);
  1335→    dying->exit_status = status;
  1336→    dying->state = PROC_ZOMBIE;
  1337→    num_procs--;
  1338→
  1339→    struct pcb *par = dying->parent;
  1340→    if (par != NULL) {
  1341→        dying->zombie_next = par->zombie_list;
  1342→        par->zombie_list   = dying;
  1343→
  1344→        if (par->state == PROC_BLOCKED) {
  1345→            /* Parent is in Wait() */
  1346→            enqueue_ready(par);
  1347→            par->state = PROC_READY;
  1348→        }
  1349→    } else {
  1350→        /* Orphan: free everything */
  1351→        free_all_r0_pages(dying);
  1352→        free_pcb(dying);
  1353→    }
