  1793→/* ---------- TtyWrite ---------- */
  1794→
  1795→static void KernelTtyWrite(ExceptionInfo *info) {
  1796→    int   tty_id = (int)info->regs[1];
  1797→    void *buf    = (void *)info->regs[2];
  1798→    int   len    = (int)info->regs[3];
  1799→
  1800→    if (tty_id < 0 || tty_id >= NUM_TERMINALS) {
  1801→        info->regs[0] = (unsigned long)ERROR;
  1802→        return;
  1803→    }
  1804→    if (len < 0 || len > TERMINAL_MAX_LINE) {
  1805→        info->regs[0] = (unsigned long)ERROR;
  1806→        return;
  1807→    }
  1808→    if (len == 0) {
  1809→        info->regs[0] = 0;
  1810→        return;
  1811→    }
  1812→    if (check_user_buf(buf, len, 0) != 0) {
  1813→        info->regs[0] = (unsigned long)ERROR;
  1814→        return;
  1815→    }
  1816→
  1817→    /* Copy to kernel buffer */
  1818→    int first_chunk = (len <= TERMINAL_MAX_LINE) ? len : TERMINAL_MAX_LINE;
  1819→    memcpy(current->tty_kbuf, buf, first_chunk);
  1820→    current->tty_buf   = buf;
  1821→    current->tty_len   = len;
  1822→    current->tty_wrote = first_chunk;
  1823→    current->tty_id    = tty_id;
  1824→    current->state     = PROC_BLOCKED;
  1825→
  1826→    if (!tty_transmitting[tty_id]) {
  1827→        tty_transmitting[tty_id] = 1;
  1828→        tty_write_blocked[tty_id] = current;
  1829→        TtyTransmit(tty_id, current->tty_kbuf, first_chunk);
  1830→    } else {
  1831→        /* Queue the write */
  1832→        current->next = tty_write_blocked[tty_id];
  1833→        /* Actually, for simplicity, wait in line */
  1834→        /* Add to end of write queue */
  1835→        struct pcb *q = tty_write_blocked[tty_id];
  1836→        if (q == NULL) {
  1837→            tty_write_blocked[tty_id] = current;
  1838→        } else {
  1839→            while (q->next != NULL) q = q->next;
  1840→            q->next = current;
  1841→        }
  1842→    }
  1843→
  1844→    /* Schedule another process */
  1845→    struct pcb *from = current;
  1846→    struct pcb *next = pick_next();
  1847→
  1848→    if (next == from) {
  1849→        /* No other process; just run */
  1850→        current->state = PROC_RUNNING;
  1851→        tty_write_blocked[tty_id] = NULL;
  1852→        tty_transmitting[tty_id] = 0;
  1853→        info->regs[0] = (unsigned long)len;
  1854→        return;
  1855→    }
  1856→
  1857→    if (next == idle_proc && !idle_proc->ctx_valid) {
  1858→        ContextSwitch(DoSwitch, &from->ctx, (void *)from, NULL);
  1859→        from->ctx_valid = 1;
  1860→        WriteRegister(REG_PTR0, (RCS421RegVal)(idle_proc->r0pt));
  1861→        WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
  1862→        current = idle_proc;
  1863→        idle_proc->state = PROC_RUNNING;
  1864→        if (idle_proc->user_pc != NULL) {
  1865→            info->pc  = idle_proc->user_pc;
  1866→            info->sp  = idle_proc->user_sp;
  1867→            info->psr = 0;
  1868→            for (int r = 0; r < NUM_REGS; r++) info->regs[r] = 0;
  1869→        }
  1870→        return;
  1871→    }
  1872→
  1873→    do_context_switch(from, next);
  1874→    /* When we return: tty_len has been set to bytes written */
  1875→    info->regs[0] = (unsigned long)from->tty_len;
  1876→}
