  1878→/* ---------- TtyRead ---------- */
  1879→
  1880→static void KernelTtyRead(ExceptionInfo *info) {
  1881→    int   tty_id = (int)info->regs[1];
  1882→    void *buf    = (void *)info->regs[2];
  1883→    int   len    = (int)info->regs[3];
  1884→
  1885→    if (tty_id < 0 || tty_id >= NUM_TERMINALS) {
  1886→        info->regs[0] = (unsigned long)ERROR;
  1887→        return;
  1888→    }
  1889→    if (len < 0) {
  1890→        info->regs[0] = (unsigned long)ERROR;
  1891→        return;
  1892→    }
  1893→    if (len == 0) {
  1894→        info->regs[0] = 0;
  1895→        return;
  1896→    }
  1897→    if (check_user_buf(buf, len, 1) != 0) {
  1898→        info->regs[0] = (unsigned long)ERROR;
  1899→        return;
  1900→    }
  1901→
  1902→    /* Check if there's buffered input */
  1903→    if (tty_inbuf[tty_id] != NULL) {
  1904→        struct tty_line *head = tty_inbuf[tty_id];
  1905→        int avail = head->len - head->pos;
  1906→        int give  = (len < avail) ? len : avail;
  1907→        memcpy(buf, head->buf + head->pos, give);
  1908→        head->pos += give;
  1909→        if (head->pos >= head->len) {
  1910→            tty_inbuf[tty_id] = head->next;
  1911→            free(head);
  1912→        }
  1913→        info->regs[0] = (unsigned long)give;
  1914→        return;
  1915→    }
  1916→
  1917→    /* Block waiting for input */
  1918→    current->tty_id  = tty_id;
  1919→    current->tty_buf = buf;
  1920→    current->tty_len = len;
  1921→    current->state   = PROC_BLOCKED;
  1922→
  1923→    /* Add to read queue */
  1924→    current->next = NULL;
  1925→    if (tty_read_blocked[tty_id] == NULL) {
  1926→        tty_read_blocked[tty_id] = current;
  1927→    } else {
  1928→        struct pcb *q = tty_read_blocked[tty_id];
  1929→        while (q->next != NULL) q = q->next;
  1930→        q->next = current;
  1931→    }
  1932→
  1933→    struct pcb *from = current;
  1934→    struct pcb *next = pick_next();
  1935→
  1936→    if (next == from) {
  1937→        current->state = PROC_RUNNING;
  1938→        info->regs[0] = (unsigned long)ERROR;
  1939→        return;
  1940→    }
  1941→
  1942→    if (next == idle_proc && !idle_proc->ctx_valid) {
  1943→        ContextSwitch(DoSwitch, &from->ctx, (void *)from, NULL);
  1944→        from->ctx_valid = 1;
  1945→        WriteRegister(REG_PTR0, (RCS421RegVal)(idle_proc->r0pt));
  1946→        WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
  1947→        current = idle_proc;
  1948→        idle_proc->state = PROC_RUNNING;
  1949→        if (idle_proc->user_pc != NULL) {
  1950→            info->pc  = idle_proc->user_pc;
  1951→            info->sp  = idle_proc->user_sp;
  1952→            info->psr = 0;
  1953→            for (int r = 0; r < NUM_REGS; r++) info->regs[r] = 0;
  1954→        }
  1955→        return;
  1956→    }
  1957→
  1958→    do_context_switch(from, next);
  1959→    /* tty_len was updated to bytes read by TrapTtyReceive */
  1960→    info->regs[0] = (unsigned long)from->tty_len;
  1961→}
