static void TrapIllegal(ExceptionInfo *info) {
    TracePrintf(0, "TrapIllegal: pid=%d code=%d - killing process\n",
                current->pid, info->code);

    /* Kill current process with ERROR status */
    info->regs[0] = ERROR;
    struct pcb *dying = current;
    dying->exit_status = ERROR;

    /* Notify parent or make zombie */
    if (dying->parent != NULL) {
        struct pcb *par = dying->parent;
        dying->zombie_next = par->zombie_list;
        par->zombie_list   = dying;
        if (par->state == PROC_BLOCKED) {
            /* Parent was waiting */
            par->state = PROC_RUNNING;
            enqueue_ready(par);
        }
    }

    free_user_pages(dying);
    dying->state = PROC_ZOMBIE;
    num_procs--;
    if (num_procs <= 0 && ready_head == NULL) {
        TracePrintf(0, "Halting: no more processes\n");
        Halt();
    }

    struct pcb *next = pick_next();
    next->state = PROC_RUNNING;
    /* Must switch to a valid process */
    WriteRegister(REG_PTR0, (RCS421RegVal)(next->r0pt));
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
    current = next;
    if (next == idle_proc && !idle_proc->ctx_valid) {
        if (idle_proc->user_pc != NULL) {
            info->pc  = idle_proc->user_pc;
            info->sp  = idle_proc->user_sp;
            info->psr = 0;
            for (int r = 0; r < NUM_REGS; r++) info->regs[r] = 0;
        }
    } else {
        /* We just switched R0 but we need to actually restore context */
        /* Since we're in a trap handler, we need to just return;
           if next has a ctx we should use ContextSwitch properly. */
        /* For simplicity when process dies, use info to run next process */
        if (next->ctx_valid) {
            /* We can't just set info since ContextSwitch manages kernel stack.
               But we already switched R0. We need to return to next's user space.
               If next has a valid user state in info-like structure... */
            /* Actually: after ContextSwitch, the kernel stack for 'next' should
               have the ExceptionInfo from when it was last preempted. But we've
               already changed R0. This is a problem. */
            /* Simplest fix: re-do the switch properly */
        }
        /* ContextSwitch from dying to next - but dying is dead... */
        /* Use a dummy PCB for the 'from' slot */
        static struct pcb dead_pcb;
        memset(&dead_pcb, 0, sizeof(dead_pcb));
        dead_pcb.ctx_valid = 0;
