    struct pcb *next = pick_next();
    next->state = PROC_RUNNING;

    /* Can't use do_context_switch since 'from' is dead */
    WriteRegister(REG_PTR0, (RCS421RegVal)(next->r0pt));
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
    current = next;

    if (next == idle_proc && !idle_proc->ctx_valid) {
        if (idle_proc->user_pc != NULL) {
            info->pc  = idle_proc->user_pc;
            info->sp  = idle_proc->user_sp;
            info->psr = 0;
