    WriteRegister(REG_PTR0, (RCS421RegVal)(dying->r0pt));
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
    ContextSwitch(DoSwitch, &dead_sink.ctx, (void *)&dead_sink, (void *)next);
    /* If we get here, we somehow continued - this shouldn't happen */
    Halt();
}

