static void KernelWait(ExceptionInfo *info) {
    int *status_ptr = (int *)info->regs[1];

    /* Validate pointer */
    if (status_ptr != NULL &&
        check_user_buf(status_ptr, sizeof(int), 1) != 0) {
        info->regs[0] = (unsigned long)ERROR;
        return;
    }

    /* Check if we have any children at all */
    int has_children = 0;
    for (int i = 0; i < MAX_PROCS; i++) {
        if (proc_pool_used[i] && proc_pool[i].parent == current) {
            has_children = 1;
            break;
        }
    }

    /* Check zombie list first */
    struct pcb *zombie = current->zombie_list;
    if (zombie != NULL) {
        current->zombie_list = zombie->zombie_next;
        int zpid = zombie->pid;
        int zstatus = zombie->exit_status;
        free_all_r0_pages(zombie);
        free_pcb(zombie);
        if (status_ptr != NULL) *status_ptr = zstatus;
        info->regs[0] = (unsigned long)zpid;
        return;
    }

    if (!has_children) {
        info->regs[0] = (unsigned long)ERROR;
        return;
    }

    /* Block until a child exits */
    current->state = PROC_BLOCKED;
    struct pcb *from = current;
    struct pcb *next = pick_next();

    if (next == idle_proc && !idle_proc->ctx_valid) {
        ContextSwitch(DoSwitch, &from->ctx, (void *)from, NULL);
        from->ctx_valid = 1;
        WriteRegister(REG_PTR0, (RCS421RegVal)(idle_proc->r0pt));
        WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
        current = idle_proc;
        idle_proc->state = PROC_RUNNING;
        if (idle_proc->user_pc != NULL) {
            info->pc  = idle_proc->user_pc;
            info->sp  = idle_proc->user_sp;
            info->psr = 0;
            for (int r = 0; r < NUM_REGS; r++) info->regs[r] = 0;
        }
        return;
    }

    do_context_switch(from, next);

    /* We've been woken up - collect zombie */
    zombie = current->zombie_list;
    if (zombie != NULL) {
        current->zombie_list = zombie->zombie_next;
        int zpid = zombie->pid;
        int zstatus = zombie->exit_status;
        free_all_r0_pages(zombie);
        free_pcb(zombie);
        if (status_ptr != NULL) *status_ptr = zstatus;
        info->regs[0] = (unsigned long)zpid;
    } else {
        info->regs[0] = (unsigned long)ERROR;
    }
}

