static struct pcb *collect_zombie(struct pcb *p, int *status_ptr) {
    struct pcb *z = p->zombie_list;
    if (z == NULL) return NULL;
    p->zombie_list = z->zombie_next;
    if (status_ptr != NULL) *status_ptr = z->exit_status;
    /* z's kstack was preserved (orphan case leaks it; but children always
     * have a parent, so free_user_pages preserved kstack which we free now). */
    free_all_r0_pages(z);
    free_pcb(z);
    return z;
}

