input.old_string:
/*
 * Schedule: switch current process (moving it to queue/blocked/zombie)
 * then run the next available process.
 * 'info' is the current ExceptionInfo for first-run idle switch.
 */
static void schedule(ExceptionInfo *info) {
    struct pcb *next = pick_next();
    if (next == current) return;

    struct pcb *from = current;

    if (next == idle_proc && !idle_proc->ctx_valid) {
        /*
         * First run of idle: can't use ContextSwitch since idle has no
         * valid ctx. Instead, save 'from' context (save-only), then
         * directly switch R0 and set ExceptionInfo to idle's user entry.
         */
        ContextSwitch(DoSwitch, &from->ctx, (void *)from, NULL);
        from->ctx_valid = 1;

        /* Now we're still on from's kernel stack - safe to switch R0 */
        WriteRegister(REG_PTR0, (RCS421RegVal)(idle_proc->r0pt));
        WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
        current = idle_proc;
        idle_proc->state = PROC_RUNNING;

        /* Modify ExceptionInfo so hardware returns to idle's user space */
        info->pc   = idle_proc->user_pc;
        info->sp   = idle_proc->user_sp;
        info->psr &= ~PSR_MODE;  /* user mode */
        for (int r = 0; r < NUM_REGS; r++) info->regs[r] = 0;
        return;
    }

    do_context_switch(from, next);
}

